'use client';

import { useState, useRef, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Search, X, TrendingUp, Clock } from 'lucide-react';
import { mockProducts } from '@/data/mockData';

// 최근 검색어 (추후 Supabase 연동 시 교체)
const RECENT_KEY = 'kitpick-recent-searches';

function getRecent(): string[] {
  if (typeof window === 'undefined') return [];
  try {
    return JSON.parse(localStorage.getItem(RECENT_KEY) || '[]');
  } catch {
    return [];
  }
}

function saveRecent(query: string) {
  if (typeof window === 'undefined') return;
  const prev = getRecent().filter((q) => q !== query);
  localStorage.setItem(RECENT_KEY, JSON.stringify([query, ...prev].slice(0, 5)));
}

export function Header() {
  const router = useRouter();
  const [query, setQuery] = useState('');
  const [focused, setFocused] = useState(false);
  const [recent, setRecent] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  // 인기 키워드 (추후 실데이터로 교체)
  const hotKeywords = ['수성의 마녀', 'MG 퍼펙트그레이드', '사자비 Ver.Ka', '윙 건담 EW'];

  // 실시간 미리보기 — 최대 4개
  const preview = query.trim().length > 0
    ? mockProducts
        .filter(
          (p) =>
            p.name.toLowerCase().includes(query.toLowerCase()) ||
            p.series.toLowerCase().includes(query.toLowerCase()) ||
            p.grade.toLowerCase().includes(query.toLowerCase())
        )
        .slice(0, 4)
    : [];

  useEffect(() => {
    if (focused) setRecent(getRecent());
  }, [focused]);

  // 바깥 클릭 시 드롭다운 닫기
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) {
        setFocused(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  function handleSearch(value: string) {
    const q = value.trim();
    if (!q) return;
    saveRecent(q);
    setFocused(false);
    setQuery('');
    router.push(`/search?q=${encodeURIComponent(q)}`);
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter') handleSearch(query);
    if (e.key === 'Escape') {
      setFocused(false);
      inputRef.current?.blur();
    }
  }

  const showDropdown = focused;

  return (
    <header className="h-14 border-b border-surface-border bg-surface-base/90 backdrop-blur-md sticky top-0 z-50 flex items-center px-4 gap-4">
      {/* 검색바 */}
      <div ref={wrapperRef} className="relative flex-1 max-w-xl">
        <div
          className={`flex items-center gap-2 bg-surface-raised border rounded-xl px-3 py-2 transition-all duration-200 ${
            focused
              ? 'border-brand-500/60 ring-1 ring-brand-500/20'
              : 'border-surface-border hover:border-surface-border-light'
          }`}
        >
          <Search className="w-4 h-4 text-zinc-500 shrink-0" />
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => setFocused(true)}
            onKeyDown={handleKeyDown}
            placeholder="키트명, 시리즈, 등급 검색..."
            className="flex-1 bg-transparent text-sm text-white placeholder:text-zinc-600 focus:outline-none"
          />
          {query && (
            <button onClick={() => setQuery('')} className="text-zinc-500 hover:text-zinc-300 transition-colors">
              <X className="w-3.5 h-3.5" />
            </button>
          )}
        </div>

        {/* 드롭다운 */}
        {showDropdown && (
          <div className="absolute top-full left-0 right-0 mt-2 bg-surface-overlay border border-surface-border rounded-xl shadow-2xl shadow-black/40 overflow-hidden z-50">

            {/* 실시간 미리보기 */}
            {preview.length > 0 && (
              <div className="p-2">
                <div className="px-3 py-1.5 text-[10px] font-semibold text-zinc-600 uppercase tracking-wider">
                  검색 결과
                </div>
                {preview.map((p) => (
                  <button
                    key={p.id}
                    onMouseDown={() => {
                      saveRecent(p.name);
                      setFocused(false);
                      setQuery('');
                      router.push(`/product/${p.id}`);
                    }}
                    className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg hover:bg-surface-raised transition-colors text-left"
                  >
                    <div className="w-8 h-8 rounded bg-surface-raised border border-surface-border shrink-0" />
                    <div className="flex-1 min-w-0">
                      <div className="text-sm text-white truncate">{p.name}</div>
                      <div className="text-xs text-zinc-500">{p.grade} · {p.series}</div>
                    </div>
                    <span className={`text-xs font-medium shrink-0 ${
                      p.decision === 'buy'      ? 'text-decision-buy' :
                      p.decision === 'wait'     ? 'text-decision-wait' :
                      p.decision === 'watch'    ? 'text-decision-watch' :
                      'text-decision-trending'
                    }`}>
                      {p.decision === 'buy' ? '구매추천' : p.decision === 'wait' ? '기다리세요' : p.decision === 'watch' ? '지켜보세요' : '트렌딩'}
                    </span>
                  </button>
                ))}
              </div>
            )}

            {/* 쿼리 없을 때 — 최근 검색 + 인기 키워드 */}
            {query.trim() === '' && (
              <>
                {recent.length > 0 && (
                  <div className="p-2 border-b border-surface-border">
                    <div className="flex items-center justify-between px-3 py-1.5">
                      <span className="text-[10px] font-semibold text-zinc-600 uppercase tracking-wider flex items-center gap-1">
                        <Clock className="w-3 h-3" /> 최근 검색
                      </span>
                      <button
                        onMouseDown={() => {
                          localStorage.removeItem(RECENT_KEY);
                          setRecent([]);
                        }}
                        className="text-[10px] text-zinc-600 hover:text-zinc-400 transition-colors"
                      >
                        전체 삭제
                      </button>
                    </div>
                    {recent.map((r) => (
                      <button
                        key={r}
                        onMouseDown={() => handleSearch(r)}
                        className="w-full flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-surface-raised transition-colors text-left"
                      >
                        <Clock className="w-3.5 h-3.5 text-zinc-600 shrink-0" />
                        <span className="text-sm text-zinc-300">{r}</span>
                      </button>
                    ))}
                  </div>
                )}

                <div className="p-2">
                  <div className="px-3 py-1.5 text-[10px] font-semibold text-zinc-600 uppercase tracking-wider flex items-center gap-1">
                    <TrendingUp className="w-3 h-3" /> 인기 검색어
                  </div>
                  <div className="flex flex-wrap gap-2 px-3 py-2">
                    {hotKeywords.map((kw) => (
                      <button
                        key={kw}
                        onMouseDown={() => handleSearch(kw)}
                        className="px-3 py-1 bg-surface-raised border border-surface-border rounded-full text-xs text-zinc-300 hover:border-brand-500/40 hover:text-brand-400 transition-colors"
                      >
                        {kw}
                      </button>
                    ))}
                  </div>
                </div>
              </>
            )}

            {/* 전체 검색 결과 링크 */}
            {query.trim().length > 0 && (
              <div className="border-t border-surface-border">
                <button
                  onMouseDown={() => handleSearch(query)}
                  className="w-full flex items-center gap-2 px-4 py-3 text-sm text-brand-400 hover:bg-surface-raised transition-colors"
                >
                  <Search className="w-3.5 h-3.5" />
                  <span>"{query}" 전체 결과 보기</span>
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* 우측 액션 */}
      <div className="flex items-center gap-2 shrink-0">
        <Link
          href="/feed"
          className="hidden sm:block text-sm text-zinc-400 hover:text-white transition-colors px-3 py-1.5"
        >
          피드
        </Link>
        <Link
          href="/profile"
          className="w-8 h-8 rounded-full bg-surface-raised border border-surface-border flex items-center justify-center text-zinc-400 hover:text-white hover:border-surface-border-light transition-colors text-xs font-bold"
        >
          N
        </Link>
      </div>
    </header>
  );
}
